SELECT E.PERSON_ID, E.EMPID, E.LOCAL_NAME, E.DEPTNO, D.ORG_NAME_LOCAL AS DEPT_NAME FROM HR_EMPLOYEE E LEFT JOIN HR_DEPARTMENT D ON D.DEPTNO = E.DEPTNO AND D.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} WHERE E.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND ( E.EMPID LIKE '%' || #{searchKeyword, jdbcType=VARCHAR} || '%' OR CONVERTTOUNSIGN(UPPER(E.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{searchKeyword, jdbcType=VARCHAR})) || '%' )
AND ROWNUM = 1 ORDER BY E.EMPID

