UPDATE HR_EXPERIENCE_INSIDE
SET ACTIVITY = '2',
    UPDATED_BY = #{adminID, jdbcType=VARCHAR},
    UPDATE_DATE = SYSDATE,
    UPDATED_IP = #{adminIP, jdbcType=VARCHAR}
WHERE SEQ = #{seq, jdbcType=NUMERIC}
